import React from 'react';
import { Routes, Route } from 'react-router-dom';
import Header from './components/Header';
import Home from './pages/Home';
import ArtistesList from './pages/ArtistesList';
import ArtisteDetail from './pages/ArtisteDetail';
import ArtisteForm from './pages/ArtisteForm';
import AlbumsList from './pages/AlbumsList';
import AlbumDetail from './pages/AlbumDetail';
import AlbumForm from './pages/AlbumForm';
import ChansonsList from './pages/ChansonsList';
import ChansonDetail from './pages/ChansonDetail';
import ChansonForm from './pages/ChansonForm';
import NotFound from './pages/NotFound';

function App() {
  return (
    <div className="min-vh-100 bg-light">
      <Header />
      <main className="container py-4">
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/artistes" element={<ArtistesList />} />
          <Route path="/artistes/create" element={<ArtisteForm />} />
          <Route path="/artistes/:id" element={<ArtisteDetail />} />
          <Route path="/artistes/:id/edit" element={<ArtisteForm />} />

          <Route path="/albums" element={<AlbumsList />} />
          <Route path="/albums/create" element={<AlbumForm />} />
          <Route path="/albums/:id" element={<AlbumDetail />} />
          <Route path="/albums/:id/edit" element={<AlbumForm />} />

          <Route path="/chansons" element={<ChansonsList />} />
          <Route path="/chansons/create" element={<ChansonForm />} />
          <Route path="/chansons/:id" element={<ChansonDetail />} />
          <Route path="/chansons/:id/edit" element={<ChansonForm />} />

          <Route path="*" element={<NotFound />} />
        </Routes>
      </main>
    </div>
  );
}

export default App;
